"use client"

import { useState, useEffect, useCallback } from "react"
import { WizardProgress } from "./WizardProgress"
import { WizardStepIdentify } from "./WizardStepIdentify"
import type { CardSearchResult, PrintOption } from "./CardSearchInput"
import type { ConditionCode } from "@/components/seller/ConditionGuide"

export interface WizardState {
  currentStep: 1 | 2 | 3
  selectedCard: CardSearchResult | null
  selectedPrint: PrintOption | null
  condition: ConditionCode
  language: string
  photos: string[]
  description: string
  price: number
  shippingMethod: string
}

interface ListingWizardProps {
  prefillSku?: string
}

export function ListingWizard({ prefillSku }: ListingWizardProps) {
  const [state, setState] = useState<WizardState>({
    currentStep: 1,
    selectedCard: null,
    selectedPrint: null,
    condition: "NM",
    language: "EN",
    photos: [],
    description: "",
    price: 0,
    shippingMethod: "standard",
  })

  const [prefillLoading, setPrefillLoading] = useState(!!prefillSku)
  const [prefillError, setPrefillError] = useState<string | null>(null)

  // Pre-fill from SKU
  useEffect(() => {
    if (!prefillSku) return

    let cancelled = false

    async function fetchSkuData() {
      try {
        const response = await fetch(
          `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/catalog/sku/${encodeURIComponent(prefillSku!)}`
        )

        if (!response.ok) {
          throw new Error(`Failed to fetch card data (${response.status})`)
        }

        const data = await response.json()

        if (cancelled) return

        const card: CardSearchResult = {
          id: data.cardId || data.id || "",
          name: data.cardName || data.name || "",
          setName: data.setName || "",
          rarity: data.rarity || "",
          imageUrl: data.imageUrl || undefined,
          prints: (data.prints || data.printings || []).map(
            (p: Record<string, unknown>) => ({
              id: p.id || "",
              setName: p.setName || p.set_name || "",
              setCode: p.setCode || p.set_code || "",
              collectorNumber: p.collectorNumber || p.collector_number || "",
              imageUrl: p.imageUrl || p.image_url || undefined,
            })
          ),
        }

        // Try to find the specific printing from the SKU data
        const matchingPrint: PrintOption | null = card.prints.find(
          (p) =>
            p.setCode === (data.setCode || "") &&
            p.collectorNumber === (data.collectorNumber || "")
        ) || card.prints[0] || null

        setState((prev) => ({
          ...prev,
          currentStep: 2,
          selectedCard: card,
          selectedPrint: matchingPrint,
        }))
      } catch (err) {
        if (cancelled) return
        const message = err instanceof Error ? err.message : "Failed to load card data"
        console.error("[listing-wizard] SKU prefill failed:", message)
        setPrefillError(message)
      } finally {
        if (!cancelled) setPrefillLoading(false)
      }
    }

    fetchSkuData()
    return () => {
      cancelled = true
    }
  }, [prefillSku])

  const completedSteps = getCompletedSteps(state)

  const handleCardSelect = useCallback((card: CardSearchResult) => {
    setState((prev) => ({
      ...prev,
      selectedCard: card,
      selectedPrint: null, // Reset print when card changes
    }))
  }, [])

  const handlePrintSelect = useCallback((print: PrintOption) => {
    setState((prev) => ({
      ...prev,
      selectedPrint: print,
    }))
  }, [])

  const goToStep = useCallback((step: 1 | 2 | 3) => {
    setState((prev) => ({ ...prev, currentStep: step }))
  }, [])

  if (prefillLoading) {
    return (
      <div
        data-testid="wizard-loading"
        style={{
          display: "flex",
          justifyContent: "center",
          padding: 48,
          color: "var(--text-tertiary)",
          fontSize: 14,
        }}
      >
        Loading card data...
      </div>
    )
  }

  if (prefillError) {
    return (
      <div
        data-testid="wizard-prefill-error"
        style={{
          padding: 24,
          background: "rgba(239,68,68,0.08)",
          border: "1px solid rgba(239,68,68,0.2)",
          borderRadius: 12,
          color: "var(--negative)",
          fontSize: 14,
          textAlign: "center",
        }}
      >
        {prefillError}
      </div>
    )
  }

  return (
    <div data-testid="listing-wizard">
      <WizardProgress currentStep={state.currentStep} completedSteps={completedSteps} />

      {state.currentStep === 1 && (
        <WizardStepIdentify
          selectedCard={state.selectedCard}
          selectedPrint={state.selectedPrint}
          onCardSelect={handleCardSelect}
          onPrintSelect={handlePrintSelect}
          onContinue={() => goToStep(2)}
        />
      )}

      {state.currentStep === 2 && (
        <div
          data-testid="wizard-step-condition"
          style={{
            background: "var(--bg-surface-1)",
            border: "1px solid var(--border-default)",
            borderRadius: 16,
            padding: 32,
            color: "var(--text-secondary)",
            fontSize: 14,
            textAlign: "center",
          }}
        >
          <h2
            style={{
              fontFamily: "var(--font-display, 'Barlow Condensed', sans-serif)",
              fontWeight: 700,
              fontSize: 24,
              color: "var(--text-primary)",
              marginBottom: 8,
            }}
          >
            Condition &amp; Photos
          </h2>
          <p style={{ color: "var(--text-tertiary)", marginBottom: 16 }}>
            Step 2 content — coming in T02
          </p>
          <div style={{ display: "flex", justifyContent: "space-between", marginTop: 32 }}>
            <button
              type="button"
              onClick={() => goToStep(1)}
              data-testid="wizard-back-btn"
              style={{
                fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
                fontWeight: 600,
                fontSize: 14,
                padding: "12px 28px",
                borderRadius: 12,
                background: "transparent",
                color: "var(--text-secondary)",
                border: "1px solid var(--border-default)",
                cursor: "pointer",
              }}
            >
              ← Back
            </button>
            <button
              type="button"
              onClick={() => goToStep(3)}
              data-testid="wizard-continue-btn"
              style={{
                fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
                fontWeight: 600,
                fontSize: 15,
                padding: "14px 32px",
                borderRadius: 12,
                border: "none",
                cursor: "pointer",
                background: "var(--brand-primary)",
                color: "white",
                boxShadow: "0 0 20px rgba(139,92,246,0.2)",
              }}
            >
              Continue →
            </button>
          </div>
        </div>
      )}

      {state.currentStep === 3 && (
        <div
          data-testid="wizard-step-price"
          style={{
            background: "var(--bg-surface-1)",
            border: "1px solid var(--border-default)",
            borderRadius: 16,
            padding: 32,
            color: "var(--text-secondary)",
            fontSize: 14,
            textAlign: "center",
          }}
        >
          <h2
            style={{
              fontFamily: "var(--font-display, 'Barlow Condensed', sans-serif)",
              fontWeight: 700,
              fontSize: 24,
              color: "var(--text-primary)",
              marginBottom: 8,
            }}
          >
            Set Your Price
          </h2>
          <p style={{ color: "var(--text-tertiary)", marginBottom: 16 }}>
            Step 3 content — coming in T03
          </p>
          <div style={{ display: "flex", justifyContent: "space-between", marginTop: 32 }}>
            <button
              type="button"
              onClick={() => goToStep(2)}
              data-testid="wizard-back-btn"
              style={{
                fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
                fontWeight: 600,
                fontSize: 14,
                padding: "12px 28px",
                borderRadius: 12,
                background: "transparent",
                color: "var(--text-secondary)",
                border: "1px solid var(--border-default)",
                cursor: "pointer",
              }}
            >
              ← Back
            </button>
            <span />
          </div>
        </div>
      )}
    </div>
  )
}

function getCompletedSteps(state: WizardState): number[] {
  const completed: number[] = []

  // Step 1 complete when card + print selected
  if (state.selectedCard && state.selectedPrint) {
    completed.push(1)
  }

  // Step 2 will be complete after condition + photos (T02)
  // Step 3 will be complete after pricing (T03)

  return completed
}

"use client"

import { cn } from "@/lib/utils"

export type ConditionCode = "NM" | "LP" | "MP" | "HP" | "DMG"

interface ConditionOption {
  code: ConditionCode
  label: string
  description: string
  examples: string
  borderColor: string
  bgColor: string
  ringColor: string
}

const CONDITIONS: ConditionOption[] = [
  {
    code: "NM",
    label: "Near Mint",
    description: "Card shows minimal to no wear. Corners are sharp, surface is clean.",
    examples: "Fresh from pack, sleeved immediately",
    borderColor: "rgba(16,185,129,0.3)",
    bgColor: "rgba(16,185,129,0.08)",
    ringColor: "rgba(16,185,129,0.6)",
  },
  {
    code: "LP",
    label: "Lightly Played",
    description: "Slight wear on edges or corners. Minor surface scratches visible at angle.",
    examples: "Played in sleeves, minor shuffling wear",
    borderColor: "rgba(132,204,22,0.3)",
    bgColor: "rgba(132,204,22,0.08)",
    ringColor: "rgba(132,204,22,0.6)",
  },
  {
    code: "MP",
    label: "Moderately Played",
    description: "Noticeable wear on edges and corners. Surface scratches visible. Still tournament legal.",
    examples: "Played unsleeved, visible edge whitening",
    borderColor: "rgba(245,158,11,0.3)",
    bgColor: "rgba(245,158,11,0.08)",
    ringColor: "rgba(245,158,11,0.6)",
  },
  {
    code: "HP",
    label: "Heavily Played",
    description: "Heavy wear throughout. May have creases, bends, or significant whitening.",
    examples: "Heavily used, noticeable creasing",
    borderColor: "rgba(249,115,22,0.3)",
    bgColor: "rgba(249,115,22,0.08)",
    ringColor: "rgba(249,115,22,0.6)",
  },
  {
    code: "DMG",
    label: "Damaged",
    description: "Major damage present. Water damage, tears, heavy creases, or writing on card.",
    examples: "Water damage, torn, written on",
    borderColor: "rgba(239,68,68,0.3)",
    bgColor: "rgba(239,68,68,0.08)",
    ringColor: "rgba(239,68,68,0.6)",
  },
]

interface ConditionGuideProps {
  value: ConditionCode
  onChange: (condition: ConditionCode) => void
  compact?: boolean
}

export function ConditionGuide({ value, onChange, compact = false }: ConditionGuideProps) {
  if (compact) {
    return (
      <div className="flex gap-2" role="radiogroup" aria-label="Card condition">
        {CONDITIONS.map((condition) => {
          const selected = value === condition.code
          return (
            <button
              key={condition.code}
              type="button"
              role="radio"
              aria-checked={selected}
              onClick={() => onChange(condition.code)}
              className={cn(
                "px-3 py-1.5 text-sm font-medium rounded-md border transition-all",
                !selected && "opacity-60 hover:opacity-100"
              )}
              style={{
                borderColor: condition.borderColor,
                background: condition.bgColor,
                ...(selected ? { boxShadow: `0 0 0 2px ${condition.ringColor}` } : {}),
              }}
            >
              {condition.code}
            </button>
          )
        })}
      </div>
    )
  }

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Card condition">
      {CONDITIONS.map((condition) => {
        const selected = value === condition.code
        return (
          <button
            key={condition.code}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => onChange(condition.code)}
            className={cn(
              "w-full text-left p-3 rounded-lg border transition-all",
              !selected && "opacity-70 hover:opacity-100"
            )}
            style={{
              borderColor: condition.borderColor,
              background: condition.bgColor,
              ...(selected ? { boxShadow: `0 0 0 2px ${condition.ringColor}` } : {}),
            }}
          >
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <span className="font-semibold text-sm">{condition.code}</span>
                <span className="text-sm text-primary">{condition.label}</span>
              </div>
              {selected && (
                <svg className="w-5 h-5 text-current" fill="currentColor" viewBox="0 0 20 20">
                  <path
                    fillRule="evenodd"
                    d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"
                    clipRule="evenodd"
                  />
                </svg>
              )}
            </div>
            <p className="text-xs text-secondary mt-1">{condition.description}</p>
            <p className="text-xs text-tertiary mt-0.5 italic">{condition.examples}</p>
          </button>
        )
      })}
    </div>
  )
}

"use server"

import { sdk } from "../config"
import { getAuthHeaders } from "./cookies"

// --- Types ---

export interface SellerDashboardStats {
  seller_id: string
  seller_name: string
  active_listings: number
  total_listings: number
  total_sales: number
  monthly_revenue: number
  pending_orders: number
  recent_activity: Array<{
    type: string
    title: string
    description: string
    amount: number
    created_at: string
  }>
}

export interface SellerListing {
  id: string
  title: string
  handle: string
  status: string
  thumbnail: string | null
  created_at: string
  updated_at: string
  variants: Array<{
    id: string
    title: string
    sku: string
    price: number
    currency_code: string
  }>
}

export interface SellerOrder {
  id: string
  display_id: number
  status: string
  created_at: string
  currency_code: string
  total: number
  items: Array<{
    title: string
    quantity: number
    unit_price: number
  }>
}

interface PaginatedResponse<T> {
  success: boolean
  data: {
    total: number
    limit: number
    offset: number
  } & T
  message?: string
}

// --- Dashboard ---

export async function getSellerDashboard(): Promise<SellerDashboardStats | null> {
  const headers = await getAuthHeaders()

  try {
    const { success, data } = await sdk.client.fetch<{
      success: boolean
      data: SellerDashboardStats
    }>("/store/consumer-seller/dashboard", {
      method: "GET",
      headers,
      cache: "no-cache",
    })

    return success ? data : null
  } catch (error) {
    console.error("[seller-dashboard] Failed to fetch dashboard:", error)
    return null
  }
}

// --- Listings ---

export async function getSellerListings(
  options: {
    status?: string
    limit?: number
    offset?: number
  } = {}
): Promise<{ listings: SellerListing[]; total: number } | null> {
  const headers = await getAuthHeaders()
  const { status = "all", limit = 20, offset = 0 } = options

  try {
    const { success, data } = await sdk.client.fetch<
      PaginatedResponse<{ listings: SellerListing[] }>
    >("/store/consumer-seller/listings", {
      method: "GET",
      headers,
      query: { status, limit, offset },
      cache: "no-cache",
    })

    return success ? { listings: data.listings, total: data.total } : null
  } catch (error) {
    console.error("[seller-dashboard] Failed to fetch listings:", error)
    return null
  }
}

export async function updateSellerListing(
  productId: string,
  updates: { status?: "published" | "draft" }
): Promise<boolean> {
  const headers = await getAuthHeaders()

  try {
    const { success } = await sdk.client.fetch<{ success: boolean }>(
      `/store/consumer-seller/listings/${productId}`,
      {
        method: "PUT",
        headers,
        body: updates,
      }
    )

    return success
  } catch (error) {
    console.error("[seller-dashboard] Failed to update listing:", error)
    return false
  }
}

export async function deleteSellerListing(productId: string): Promise<boolean> {
  const headers = await getAuthHeaders()

  try {
    const { success } = await sdk.client.fetch<{ success: boolean }>(
      `/store/consumer-seller/listings/${productId}`,
      {
        method: "DELETE",
        headers,
      }
    )

    return success
  } catch (error) {
    console.error("[seller-dashboard] Failed to delete listing:", error)
    return false
  }
}

// --- Listing Creation ---

export interface CreateListingInput {
  catalog_sku: string
  condition: "NM" | "LP" | "MP" | "HP" | "DMG"
  language?: string
  finish?: string
  price: number
  quantity?: number
  title: string
  description?: string
  images?: string[]
  shipping_method?: "standard" | "priority" | "free_over_25"
}

export interface CreateListingResult {
  listing_id: string
  title: string
  handle: string
  status: "published" | "draft"
  thumbnail: string | null
  variant_id: string
  sku: string
  price: number
  quantity: number
  condition: string
  shipping_method: string
}

export async function uploadListingImage(file: File): Promise<string | null> {
  const headers = await getAuthHeaders()

  try {
    const formData = new FormData()
    formData.append("files", file)

    const response = await fetch(
      `${process.env.NEXT_PUBLIC_MEDUSA_BACKEND_URL}/store/consumer-seller/uploads`,
      {
        method: "POST",
        headers: headers as Record<string, string>,
        body: formData,
      }
    )

    if (!response.ok) return null

    const data = await response.json()
    return data.files?.[0]?.url || null
  } catch (error) {
    console.error("[seller-dashboard] Failed to upload image:", error)
    return null
  }
}

export async function createSellerListing(
  input: CreateListingInput
): Promise<CreateListingResult | null> {
  const headers = await getAuthHeaders()

  try {
    const { success, data } = await sdk.client.fetch<{
      success: boolean
      data: CreateListingResult
    }>("/store/consumer-seller/listings", {
      method: "POST",
      headers,
      body: {
        ...input,
        status: "published",
      },
    })

    return success ? data : null
  } catch (error) {
    console.error("[seller-dashboard] Failed to create listing:", error)
    return null
  }
}

export async function saveListingDraft(
  input: CreateListingInput
): Promise<CreateListingResult | null> {
  const headers = await getAuthHeaders()

  try {
    const { success, data } = await sdk.client.fetch<{
      success: boolean
      data: CreateListingResult
    }>("/store/consumer-seller/listings", {
      method: "POST",
      headers,
      body: {
        ...input,
        status: "draft",
      },
    })

    return success ? data : null
  } catch (error) {
    console.error("[seller-dashboard] Failed to save listing draft:", error)
    return null
  }
}

// --- Orders ---

export async function getSellerOrders(
  options: {
    limit?: number
    offset?: number
  } = {}
): Promise<{ orders: SellerOrder[]; total: number } | null> {
  const headers = await getAuthHeaders()
  const { limit = 20, offset = 0 } = options

  try {
    const { success, data } = await sdk.client.fetch<
      PaginatedResponse<{ orders: SellerOrder[] }>
    >("/store/consumer-seller/orders", {
      method: "GET",
      headers,
      query: { limit, offset },
      cache: "no-cache",
    })

    return success ? { orders: data.orders, total: data.total } : null
  } catch (error) {
    console.error("[seller-dashboard] Failed to fetch orders:", error)
    return null
  }
}

import { render, screen, fireEvent, waitFor, act } from "@testing-library/react"
import { describe, it, expect, vi, beforeEach, afterEach } from "vitest"
import { ListingWizard } from "../wizard/ListingWizard"
import { WizardProgress } from "../wizard/WizardProgress"
import { CardSearchInput } from "../wizard/CardSearchInput"
import { PrintingGrid } from "../wizard/PrintingGrid"
import { WizardStepIdentify } from "../wizard/WizardStepIdentify"
import type { CardSearchResult, PrintOption } from "../wizard/CardSearchInput"

// --- Mocks ---

const mockCard: CardSearchResult = {
  id: "card-1",
  name: "Ragavan, Nimble Pilferer",
  setName: "Modern Horizons 2",
  rarity: "Mythic Rare",
  prints: [
    {
      id: "print-1",
      setName: "Modern Horizons 2",
      setCode: "MH2",
      collectorNumber: "138",
    },
    {
      id: "print-2",
      setName: "MH2 (Extended Art)",
      setCode: "MH2",
      collectorNumber: "382",
    },
  ],
}

const mockPrint: PrintOption = mockCard.prints[0]

function mockFetchSuccess(data: unknown) {
  return vi.fn().mockResolvedValue({
    ok: true,
    json: () => Promise.resolve(data),
  })
}

function mockFetchError(status = 500) {
  return vi.fn().mockResolvedValue({
    ok: false,
    status,
    json: () => Promise.resolve({ error: "Server error" }),
  })
}

// --- WizardProgress ---

describe("WizardProgress", () => {
  it("renders 3 step indicators", () => {
    render(<WizardProgress currentStep={1} completedSteps={[]} />)

    expect(screen.getByTestId("wizard-progress")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-step-dot-1")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-step-dot-2")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-step-dot-3")).toBeInTheDocument()
  })

  it("shows step 1 as active with brand-primary background", () => {
    render(<WizardProgress currentStep={1} completedSteps={[]} />)

    const dot1 = screen.getByTestId("wizard-step-dot-1")
    expect(dot1.textContent).toBe("1")
    expect(dot1.style.background).toBe("var(--brand-primary)")
  })

  it("shows completed step with checkmark and positive background", () => {
    render(<WizardProgress currentStep={2} completedSteps={[1]} />)

    const dot1 = screen.getByTestId("wizard-step-dot-1")
    expect(dot1.textContent).toBe("✓")
    expect(dot1.style.background).toBe("var(--positive)")
  })

  it("shows pending step with surface-3 background", () => {
    render(<WizardProgress currentStep={1} completedSteps={[]} />)

    const dot3 = screen.getByTestId("wizard-step-dot-3")
    expect(dot3.textContent).toBe("3")
    expect(dot3.style.background).toBe("var(--bg-surface-3)")
  })

  it("renders connectors between steps", () => {
    render(<WizardProgress currentStep={2} completedSteps={[1]} />)

    const connector1 = screen.getByTestId("wizard-connector-1")
    expect(connector1).toBeInTheDocument()
    // Completed connector should use positive color
    expect(connector1.style.background).toBe("var(--positive)")
  })

  it("shows step labels", () => {
    render(<WizardProgress currentStep={1} completedSteps={[]} />)

    // Full and short labels both render (short hidden via CSS), so use getAllByText
    expect(screen.getAllByText("Identify").length).toBeGreaterThanOrEqual(1)
    expect(screen.getByText("Condition + Photos")).toBeInTheDocument()
    expect(screen.getByText("Price + Confirm")).toBeInTheDocument()
  })
})

// --- CardSearchInput ---

describe("CardSearchInput", () => {
  beforeEach(() => {
    vi.useFakeTimers({ shouldAdvanceTime: true })
  })

  afterEach(() => {
    vi.useRealTimers()
    vi.restoreAllMocks()
  })

  it("renders search input", () => {
    render(<CardSearchInput onCardSelect={vi.fn()} selectedCard={null} />)

    expect(screen.getByTestId("card-search-field")).toBeInTheDocument()
    expect(screen.getByPlaceholderText("Search by card name...")).toBeInTheDocument()
  })

  it("debounces search at 300ms", async () => {
    const fetchMock = mockFetchSuccess({ cards: [mockCard] })
    global.fetch = fetchMock

    render(<CardSearchInput onCardSelect={vi.fn()} selectedCard={null} />)

    const input = screen.getByTestId("card-search-field")
    await act(async () => {
      fireEvent.change(input, { target: { value: "Ragavan" } })
    })

    // Not called yet
    expect(fetchMock).not.toHaveBeenCalled()

    // Advance past debounce
    await act(async () => {
      vi.advanceTimersByTime(350)
    })

    await waitFor(() => {
      expect(fetchMock).toHaveBeenCalledTimes(1)
    })
    expect(fetchMock).toHaveBeenCalledWith(
      expect.stringContaining("/api/catalog/cards/search?q=Ragavan")
    )
  })

  it("renders search results", async () => {
    global.fetch = mockFetchSuccess({ cards: [mockCard] })

    render(<CardSearchInput onCardSelect={vi.fn()} selectedCard={null} />)

    const input = screen.getByTestId("card-search-field")
    await act(async () => {
      fireEvent.change(input, { target: { value: "Ragavan" } })
    })

    await act(async () => {
      vi.advanceTimersByTime(350)
    })

    await waitFor(() => {
      expect(screen.getByTestId("card-search-results")).toBeInTheDocument()
    })

    expect(screen.getByText("Ragavan, Nimble Pilferer")).toBeInTheDocument()
    expect(screen.getByText("Modern Horizons 2 — Mythic Rare")).toBeInTheDocument()
  })

  it("calls onCardSelect when a result is clicked", async () => {
    global.fetch = mockFetchSuccess({ cards: [mockCard] })
    const onCardSelect = vi.fn()

    render(<CardSearchInput onCardSelect={onCardSelect} selectedCard={null} />)

    const input = screen.getByTestId("card-search-field")
    await act(async () => {
      fireEvent.change(input, { target: { value: "Ragavan" } })
    })

    await act(async () => {
      vi.advanceTimersByTime(350)
    })

    await waitFor(() => {
      expect(screen.getByTestId("card-search-results")).toBeInTheDocument()
    })

    const resultItem = screen.getByTestId("card-search-result-item")
    fireEvent.click(resultItem)

    expect(onCardSelect).toHaveBeenCalledWith(mockCard)
  })

  it("shows error state on API failure", async () => {
    global.fetch = mockFetchError(500)

    render(<CardSearchInput onCardSelect={vi.fn()} selectedCard={null} />)

    const input = screen.getByTestId("card-search-field")
    await act(async () => {
      fireEvent.change(input, { target: { value: "Ragavan" } })
    })

    await act(async () => {
      vi.advanceTimersByTime(350)
    })

    await waitFor(() => {
      expect(screen.getByTestId("card-search-error")).toBeInTheDocument()
    })
  })

  it("does not search for queries shorter than 2 characters", async () => {
    const fetchMock = mockFetchSuccess({ cards: [] })
    global.fetch = fetchMock

    render(<CardSearchInput onCardSelect={vi.fn()} selectedCard={null} />)

    const input = screen.getByTestId("card-search-field")
    await act(async () => {
      fireEvent.change(input, { target: { value: "R" } })
    })

    await act(async () => {
      vi.advanceTimersByTime(350)
    })

    expect(fetchMock).not.toHaveBeenCalled()
  })
})

// --- PrintingGrid ---

describe("PrintingGrid", () => {
  it("renders nothing when prints array is empty", () => {
    const { container } = render(
      <PrintingGrid prints={[]} selectedPrint={null} onSelect={vi.fn()} />
    )
    expect(container.innerHTML).toBe("")
  })

  it("renders printing options", () => {
