})

// --- WizardStepIdentify ---

describe("WizardStepIdentify", () => {
  it("renders Find Your Card title", () => {
    render(
      <WizardStepIdentify
        selectedCard={null}
        selectedPrint={null}
        onCardSelect={vi.fn()}
        onPrintSelect={vi.fn()}
        onContinue={vi.fn()}
      />
    )

    expect(screen.getByText("Find Your Card")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-step-identify")).toBeInTheDocument()
  })

  it("disables Continue when no print selected", () => {
    render(
      <WizardStepIdentify
        selectedCard={null}
        selectedPrint={null}
        onCardSelect={vi.fn()}
