  })

  it("enables Continue when card and print are selected", () => {
    render(
      <WizardStepIdentify
        selectedCard={mockCard}
        selectedPrint={mockPrint}
        onCardSelect={vi.fn()}
        onPrintSelect={vi.fn()}
        onContinue={vi.fn()}
      />
    )

    const btn = screen.getByTestId("wizard-continue-btn")
    expect(btn).not.toBeDisabled()
  })

  it("calls onContinue when Continue is clicked", () => {
    const onContinue = vi.fn()

    render(
      <WizardStepIdentify
        selectedCard={mockCard}
        selectedPrint={mockPrint}
        onCardSelect={vi.fn()}
        onPrintSelect={vi.fn()}
        onContinue={onContinue}
      />
    )

    fireEvent.click(screen.getByTestId("wizard-continue-btn"))
    expect(onContinue).toHaveBeenCalledTimes(1)
  })

  it("shows printing grid when card is selected", () => {
    render(
      <WizardStepIdentify
        selectedCard={mockCard}
        selectedPrint={null}
        onCardSelect={vi.fn()}
        onPrintSelect={vi.fn()}
        onContinue={vi.fn()}
      />
