    expect(screen.getByTestId("printing-grid")).toBeInTheDocument()
  })

  it("hides printing grid when no card selected", () => {
    render(
      <WizardStepIdentify
        selectedCard={null}
        selectedPrint={null}
        onCardSelect={vi.fn()}
        onPrintSelect={vi.fn()}
        onContinue={vi.fn()}
      />
    )

    expect(screen.queryByTestId("printing-grid")).not.toBeInTheDocument()
  })
})

// --- ListingWizard (integration) ---

describe("ListingWizard", () => {
  afterEach(() => {
    vi.useRealTimers()
    vi.restoreAllMocks()
  })

  it("renders wizard with step 1 active", () => {
    render(<ListingWizard />)

    expect(screen.getByTestId("listing-wizard")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-progress")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-step-identify")).toBeInTheDocument()

    // Step 1 dot should be active
    const dot1 = screen.getByTestId("wizard-step-dot-1")
    expect(dot1.style.background).toBe("var(--brand-primary)")
  })

  it("advances to step 2 when Continue clicked after selecting card and print", async () => {
    vi.useFakeTimers({ shouldAdvanceTime: true })
    global.fetch = mockFetchSuccess({ cards: [mockCard] })

    render(<ListingWizard />)

    // Search for a card
    const input = screen.getByTestId("card-search-field")
    await act(async () => {
      fireEvent.change(input, { target: { value: "Ragavan" } })
    })

    await act(async () => {
      vi.advanceTimersByTime(350)
    })

    await waitFor(() => {
      expect(screen.getByTestId("card-search-results")).toBeInTheDocument()
    })

    // Select a card
    await act(async () => {
      fireEvent.click(screen.getByTestId("card-search-result-item"))
    })

    await waitFor(() => {
      expect(screen.getByTestId("printing-grid")).toBeInTheDocument()
    })

    // Select a print
    const printOptions = screen.getAllByTestId("printing-option")
    await act(async () => {
      fireEvent.click(printOptions[0])
    })

    // Continue should be enabled, click it
    const continueBtn = screen.getByTestId("wizard-continue-btn")
    expect(continueBtn).not.toBeDisabled()
    await act(async () => {
      fireEvent.click(continueBtn)
    })

    // Should be on step 2 now
    await waitFor(() => {
      expect(screen.getByTestId("wizard-step-condition")).toBeInTheDocument()
    })

    // Step 1 should be marked done
    const dot1 = screen.getByTestId("wizard-step-dot-1")
    expect(dot1.textContent).toBe("✓")
    expect(dot1.style.background).toBe("var(--positive)")
  })

  it("renders with prefillSku and starts at step 2", async () => {
    global.fetch = mockFetchSuccess({
      cardId: "card-1",
      cardName: "Ragavan, Nimble Pilferer",
      setName: "Modern Horizons 2",
      setCode: "MH2",
      collectorNumber: "138",
      rarity: "Mythic Rare",
      prints: [
        {
          id: "print-1",
          setName: "Modern Horizons 2",
          setCode: "MH2",
          collectorNumber: "138",
        },
      ],
    })

    await act(async () => {
      render(<ListingWizard prefillSku="MTG-MH2-138-EN-NM-NORMAL" />)
    })

    // Should show loading first or have already transitioned
    await waitFor(() => {
      expect(screen.getByTestId("wizard-step-condition")).toBeInTheDocument()
    })
  })

  it("shows error when prefillSku fetch fails", async () => {
    global.fetch = mockFetchError(404)

    await act(async () => {
      render(<ListingWizard prefillSku="INVALID-SKU" />)
    })

    await waitFor(() => {
      expect(screen.getByTestId("wizard-prefill-error")).toBeInTheDocument()
    })
  })
})

// --- Voltage compliance ---

describe("Voltage token compliance", () => {
  it("no forbidden Tailwind color classes in wizard sources", async () => {
    // This test checks that we don't use bg-white, bg-gray-*, text-gray-* in wizard components
    // It's verified at build time via grep in slice verification, but we also assert at runtime
    // by checking that none of the rendered elements use those classes
    render(<ListingWizard />)

    const wizard = screen.getByTestId("listing-wizard")
    const html = wizard.innerHTML

    expect(html).not.toContain("bg-white")
    expect(html).not.toMatch(/bg-gray-/)
    expect(html).not.toMatch(/text-gray-/)
  })
})

