"use client"

import type { ConditionCode } from "@/components/seller/ConditionGuide"

interface ConditionOption {
  code: ConditionCode
  label: string
}

const CONDITIONS: ConditionOption[] = [
  { code: "NM", label: "Near Mint" },
  { code: "LP", label: "Lightly Played" },
  { code: "MP", label: "Moderately Played" },
  { code: "HP", label: "Heavily Played" },
  { code: "DMG", label: "Damaged" },
]

interface ConditionGradeSelectorProps {
  value: ConditionCode
  onChange: (condition: ConditionCode) => void
}

export function ConditionGradeSelector({ value, onChange }: ConditionGradeSelectorProps) {
  return (
    <div
      role="radiogroup"
      aria-label="Card condition"
      data-testid="condition-grade-selector"
      style={{
        display: "flex",
        gap: 8,
        flexWrap: "wrap",
      }}
    >
      {CONDITIONS.map((condition) => {
        const selected = value === condition.code

        return (
          <button
            key={condition.code}
            type="button"
            role="radio"
            aria-checked={selected}
            data-testid={`condition-option-${condition.code}`}
            onClick={() => onChange(condition.code)}
            style={{
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              gap: 6,
              padding: "14px 16px",
              background: selected
                ? "rgba(16,185,129,0.06)"
                : "var(--bg-surface-2)",
              border: `1px solid ${selected ? "var(--positive)" : "var(--border-default)"}`,
              borderRadius: 12,
              cursor: "pointer",
              minWidth: 72,
              transition: "all 0.15s",
            }}
          >
            {/* Placeholder thumbnail */}
            <div
              style={{
                width: 40,
                height: 56,
                background: "var(--bg-surface-3)",
                borderRadius: 4,
                border: "1px solid var(--border-default)",
              }}
            />
            {/* Condition code */}
            <span
              style={{
                fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
                fontWeight: 700,
                fontSize: 14,
                color: "var(--text-primary)",
              }}
            >
              {condition.code}
            </span>
            {/* Label */}
            <span
              style={{
                fontSize: 10,
                color: "var(--text-tertiary)",
              }}
            >
              {condition.label}
            </span>
          </button>
        )
      })}
    </div>
  )
}

"use client"

import { useRef, useState, useCallback } from "react"

interface PhotoZone {
  label: string
  url: string | null
  uploading: boolean
  error: string | null
}

interface PhotoUploaderProps {
  photos: string[]
  onPhotosChange: (photos: string[]) => void
  uploadImage: (file: File) => Promise<string | null>
}

export function PhotoUploader({ photos, onPhotosChange, uploadImage }: PhotoUploaderProps) {
  const [zones, setZones] = useState<[PhotoZone, PhotoZone]>([
    { label: "Front of Card", url: photos[0] || null, uploading: false, error: null },
    { label: "Back of Card", url: photos[1] || null, uploading: false, error: null },
  ])

  const fileInputRefs = [useRef<HTMLInputElement>(null), useRef<HTMLInputElement>(null)]

  const handleUpload = useCallback(
    async (file: File, zoneIndex: 0 | 1) => {
      setZones((prev) => {
        const next = [...prev] as [PhotoZone, PhotoZone]
        next[zoneIndex] = { ...next[zoneIndex], uploading: true, error: null }
        return next
      })

      try {
        const url = await uploadImage(file)

        if (!url) {
          throw new Error("Upload returned no URL")
        }

        setZones((prev) => {
          const next = [...prev] as [PhotoZone, PhotoZone]
          next[zoneIndex] = { ...next[zoneIndex], url, uploading: false }

          // Update parent state
          const newPhotos = [next[0].url, next[1].url].filter(Boolean) as string[]
          onPhotosChange(newPhotos)

          return next
        })
      } catch (err) {
        const message = err instanceof Error ? err.message : "Upload failed"
        console.error("[listing-wizard] Image upload failed:", message)

        setZones((prev) => {
          const next = [...prev] as [PhotoZone, PhotoZone]
          next[zoneIndex] = { ...next[zoneIndex], uploading: false, error: message }
          return next
        })
      }
    },
    [uploadImage, onPhotosChange]
  )

  const handleFileSelect = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>, zoneIndex: 0 | 1) => {
      const file = e.target.files?.[0]
      if (file) handleUpload(file, zoneIndex)
      // Reset input so same file can be re-selected
      e.target.value = ""
    },
    [handleUpload]
  )

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
  }, [])

  const handleDrop = useCallback(
    (e: React.DragEvent, zoneIndex: 0 | 1) => {
      e.preventDefault()
      e.stopPropagation()
      const file = e.dataTransfer.files?.[0]
      if (file && file.type.startsWith("image/")) {
        handleUpload(file, zoneIndex)
      }
    },
    [handleUpload]
  )

  const handleRemove = useCallback(
    (zoneIndex: 0 | 1) => {
      setZones((prev) => {
        const next = [...prev] as [PhotoZone, PhotoZone]
        next[zoneIndex] = { ...next[zoneIndex], url: null, error: null }

        const newPhotos = [next[0].url, next[1].url].filter(Boolean) as string[]
        onPhotosChange(newPhotos)

        return next
      })
    },
    [onPhotosChange]
  )

  return (
    <div
      data-testid="photo-uploader"
      style={{
        display: "grid",
        gridTemplateColumns: "1fr 1fr",
        gap: 16,
        marginBottom: 24,
      }}
    >
      {zones.map((zone, index) => (
        <div key={index}>
          {zone.url ? (
            // Preview state
            <div
              data-testid={`photo-zone-${index}`}
              style={{
                position: "relative",
                aspectRatio: "5 / 7",
                borderRadius: 14,
                overflow: "hidden",
                border: "1px solid var(--border-default)",
              }}
            >
              <img
                src={zone.url}
                alt={zone.label}
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "cover",
                }}
              />
              {/* Remove overlay */}
              <button
                type="button"
                data-testid={`photo-remove-${index}`}
                onClick={() => handleRemove(index as 0 | 1)}
                style={{
                  position: "absolute",
                  top: 8,
                  right: 8,
                  width: 28,
                  height: 28,
                  borderRadius: "50%",
                  background: "rgba(0,0,0,0.6)",
                  border: "none",
                  color: "white",
                  cursor: "pointer",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: 14,
                }}
                aria-label={`Remove ${zone.label}`}
              >
                ✕
              </button>
            </div>
          ) : (
            // Upload zone
            <div
              data-testid={`photo-zone-${index}`}
              onClick={() => fileInputRefs[index].current?.click()}
              onDragOver={handleDragOver}
              onDrop={(e) => handleDrop(e, index as 0 | 1)}
              style={{
                aspectRatio: "5 / 7",
                border: "2px dashed var(--border-strong)",
                borderRadius: 14,
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                justifyContent: "center",
                gap: 10,
                background: "var(--bg-surface-2)",
                cursor: zone.uploading ? "wait" : "pointer",
                transition: "all 0.15s",
              }}
            >
              {zone.uploading ? (
                <div
                  data-testid={`photo-loading-${index}`}
                  style={{
                    width: 32,
                    height: 32,
                    border: "3px solid var(--border-default)",
                    borderTop: "3px solid var(--brand-primary)",
                    borderRadius: "50%",
                    animation: "spin 0.8s linear infinite",
                  }}
                />
              ) : (
                <>
                  {/* Camera/image icon */}
                  <svg
                    width="40"
                    height="40"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="1.5"
                    style={{ color: "var(--text-tertiary)" }}
                  >
                    <rect x="3" y="3" width="18" height="18" rx="2" />
                    <circle cx="8.5" cy="8.5" r="1.5" />
                    <path d="m21 15-5-5L5 21" />
                  </svg>
                  <span
                    style={{
                      fontSize: 13,
                      fontWeight: 500,
                      color: "var(--text-secondary)",
                    }}
                  >
                    {zone.label}
                  </span>
                  <span
                    style={{
                      fontSize: 11,
                      color: "var(--text-tertiary)",
                    }}
                  >
                    Drag & drop or click to upload
                  </span>
                </>
              )}

              {zone.error && (
                <span
                  data-testid={`photo-error-${index}`}
                  style={{
                    fontSize: 11,
                    color: "var(--negative)",
                    marginTop: 4,
                  }}
                >
                  {zone.error}
                </span>
              )}
            </div>
          )}

          <input
            ref={fileInputRefs[index]}
            type="file"
            accept="image/*"
            data-testid={`photo-input-${index}`}
            style={{ display: "none" }}
            onChange={(e) => handleFileSelect(e, index as 0 | 1)}
          />
        </div>
      ))}

      {/* Spinner animation */}
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  )
}

"use client"

import { useState } from "react"
import { ConditionGradeSelector } from "./ConditionGradeSelector"
import { PhotoUploader } from "./PhotoUploader"
import type { ConditionCode } from "@/components/seller/ConditionGuide"

interface WizardStepConditionProps {
  condition: ConditionCode
  photos: string[]
  description: string
  onConditionChange: (condition: ConditionCode) => void
  onPhotosChange: (photos: string[]) => void
  onDescriptionChange: (description: string) => void
  onBack: () => void
  onContinue: () => void
  uploadImage: (file: File) => Promise<string | null>
}

export function WizardStepCondition({
  condition,
  photos,
  description,
  onConditionChange,
  onPhotosChange,
  onDescriptionChange,
  onBack,
  onContinue,
  uploadImage,
}: WizardStepConditionProps) {
  const [showPhotoNudge, setShowPhotoNudge] = useState(false)

  const handleContinue = () => {
    if (photos.length === 0) {
      setShowPhotoNudge(true)
      // Still allow continuing — just nudge
      setTimeout(() => onContinue(), 0)
    } else {
      onContinue()
    }
  }

  return (
    <div
      data-testid="wizard-step-condition"
      style={{
        background: "var(--bg-surface-1)",
        border: "1px solid var(--border-default)",
        borderRadius: 16,
        padding: 32,
      }}
    >
      <h2
        style={{
          fontFamily: "var(--font-display, 'Barlow Condensed', sans-serif)",
          fontWeight: 700,
          fontSize: 24,
          color: "var(--text-primary)",
          marginBottom: 8,
        }}
      >
        Condition &amp; Photos
      </h2>
      <p
        style={{
          fontSize: 14,
          color: "var(--text-secondary)",
          marginBottom: 28,
          lineHeight: 1.6,
        }}
      >
        Grade the condition of your card and upload photos. Accurate grading
        builds buyer trust and reduces returns.
      </p>

      {/* Condition Selector */}
      <div style={{ marginBottom: 24 }}>
        <label
          style={{
            display: "block",
            fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
            fontSize: 13,
            fontWeight: 600,
            color: "var(--text-secondary)",
            marginBottom: 8,
          }}
        >
          Condition Grade
        </label>
        <ConditionGradeSelector value={condition} onChange={onConditionChange} />
      </div>

      {/* Photos */}
      <div style={{ marginBottom: 24 }}>
        <label
          style={{
            display: "block",
            fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
            fontSize: 13,
            fontWeight: 600,
            color: "var(--text-secondary)",
            marginBottom: 8,
          }}
        >
          Photos
        </label>
        <PhotoUploader
          photos={photos}
          onPhotosChange={onPhotosChange}
          uploadImage={uploadImage}
        />
      </div>

      {/* Photo nudge message */}
      {showPhotoNudge && photos.length === 0 && (
        <div
          data-testid="photo-nudge"
          style={{
            padding: "10px 16px",
            background: "rgba(245,158,11,0.08)",
            border: "1px solid rgba(245,158,11,0.2)",
            borderRadius: 10,
            fontSize: 13,
            color: "var(--warning)",
            marginBottom: 16,
          }}
        >
          📸 Listings with photos sell 3x faster
        </div>
      )}

      {/* Description */}
      <div style={{ marginBottom: 24 }}>
        <label
          style={{
            display: "block",
            fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
            fontSize: 13,
            fontWeight: 600,
            color: "var(--text-secondary)",
            marginBottom: 8,
          }}
        >
          Additional Notes (optional)
        </label>
        <textarea
          data-testid="condition-description"
          value={description}
          onChange={(e) => onDescriptionChange(e.target.value)}
          placeholder="Describe any notable wear, whitening, or defects..."
          style={{
            width: "100%",
            minHeight: 80,
            padding: "12px 16px",
