"use client"

import { useEffect, useState } from "react"

export interface MarketPrices {
  low: number
  median: number
  high: number
  lowPercentile?: string
  highPercentile?: string
}

interface MarketPriceDisplayProps {
  gameCode: string
  setCode: string
  collectorNumber: string
  onPricesLoaded: (prices: MarketPrices | null) => void
}

export function MarketPriceDisplay({
  gameCode,
  setCode,
  collectorNumber,
  onPricesLoaded,
}: MarketPriceDisplayProps) {
  const [prices, setPrices] = useState<MarketPrices | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(false)

  useEffect(() => {
    let cancelled = false

    async function fetchPrices() {
      setLoading(true)
      setError(false)

      try {
        const url = `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/catalog/sku/${encodeURIComponent(gameCode)}/${encodeURIComponent(setCode)}/${encodeURIComponent(collectorNumber)}/prices`
        const response = await fetch(url)

        if (!response.ok) {
          throw new Error(`Price fetch failed (${response.status})`)
        }

        const data = await response.json()

        if (cancelled) return

        if (data.low != null && data.median != null && data.high != null) {
          const marketPrices: MarketPrices = {
            low: data.low,
            median: data.median,
            high: data.high,
            lowPercentile: data.lowPercentile || "10th percentile",
            highPercentile: data.highPercentile || "90th percentile",
          }
          setPrices(marketPrices)
          onPricesLoaded(marketPrices)
        } else {
          setPrices(null)
          onPricesLoaded(null)
        }
      } catch (err) {
        if (cancelled) return
        const message = err instanceof Error ? err.message : "Failed to fetch market prices"
        console.error("[listing-wizard] Market price fetch failed:", message)
        setError(true)
        setPrices(null)
        onPricesLoaded(null)
      } finally {
        if (!cancelled) setLoading(false)
      }
    }

    fetchPrices()
    return () => {
      cancelled = true
    }
  }, [gameCode, setCode, collectorNumber, onPricesLoaded])

  const formatPrice = (cents: number) =>
    new Intl.NumberFormat("en-US", {
      style: "currency",
      currency: "USD",
    }).format(cents / 100)

  if (loading) {
    return (
      <div
        data-testid="market-prices-loading"
        style={{
          padding: 24,
          textAlign: "center",
          color: "var(--text-tertiary)",
          fontSize: 14,
        }}
      >
        Loading market prices...
      </div>
    )
  }

  if (error || !prices) {
    return (
      <div
        data-testid="market-prices-fallback"
        style={{
          padding: 20,
          background: "var(--bg-surface-2)",
          border: "1px solid var(--border-default)",
          borderRadius: 10,
          textAlign: "center",
          fontSize: 14,
          color: "var(--text-secondary)",
          marginBottom: 24,
        }}
      >
        No market data available — set your own price
      </div>
    )
  }

  const priceCards = [
    {
      label: "Low",
      value: prices.low,
      note: prices.lowPercentile || "10th percentile",
      color: "var(--positive)",
      borderColor: "var(--border-default)",
    },
    {
      label: "Median",
      value: prices.median,
      note: "Recommended",
      color: "var(--text-primary)",
      borderColor: "var(--brand-primary)",
    },
    {
      label: "High",
      value: prices.high,
      note: prices.highPercentile || "90th percentile",
      color: "var(--warning)",
      borderColor: "var(--border-default)",
    },
  ]

  return (
    <div
      data-testid="market-prices"
      style={{
        display: "grid",
        gridTemplateColumns: "repeat(3, 1fr)",
        gap: 12,
        marginBottom: 24,
      }}
    >
      {priceCards.map((card) => (
        <div
          key={card.label}
          data-testid={`market-price-${card.label.toLowerCase()}`}
          style={{
            padding: 16,
            background: "var(--bg-surface-2)",
            border: `1px solid ${card.borderColor}`,
            borderRadius: 10,
            textAlign: "center",
          }}
        >
          <div
            style={{
              fontSize: 11,
              color: "var(--text-tertiary)",
              textTransform: "uppercase",
              letterSpacing: "0.08em",
              fontWeight: 600,
              marginBottom: 6,
            }}
          >
            {card.label}
          </div>
          <div
            style={{
              fontFamily: "var(--font-display, 'Barlow Condensed', sans-serif)",
              fontSize: 22,
              fontWeight: 700,
              color: card.color,
            }}
          >
            {formatPrice(card.value)}
          </div>
          <div
            style={{
              fontSize: 10,
              color: "var(--text-tertiary)",
              marginTop: 2,
            }}
          >
            {card.note}
          </div>
        </div>
      ))}

      {/* Responsive: mobile single column */}
      <style>{`
        @media (max-width: 640px) {
          [data-testid="market-prices"] {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </div>
  )
}

"use client"

interface CompetitiveGaugeProps {
  price: number // in cents
  low: number // in cents
  high: number // in cents
  median: number // in cents
}

export function CompetitiveGauge({ price, low, high, median }: CompetitiveGaugeProps) {
  // Calculate marker position as percentage
  const range = high - low
  let position = 50 // default center if no range
  if (range > 0) {
    position = Math.max(0, Math.min(100, ((price - low) / range) * 100))
  }

  // Warning: price is significantly below market average (>50% below median)
  const significantlyBelow = median > 0 && price < median * 0.5

  return (
    <div
      data-testid="competitive-gauge"
      style={{
        marginBottom: 24,
        padding: 20,
        background: "var(--bg-surface-2)",
        border: "1px solid var(--border-default)",
        borderRadius: 12,
      }}
    >
      <div
        style={{
          fontSize: 13,
          fontWeight: 600,
          color: "var(--text-secondary)",
          marginBottom: 12,
        }}
      >
        Competitive Position
      </div>

      {/* Gradient bar */}
      <div
        style={{
          height: 8,
          background: "linear-gradient(90deg, var(--positive), var(--warning), var(--negative))",
          borderRadius: 999,
          position: "relative",
          marginBottom: 8,
        }}
      >
        {/* Marker */}
        <div
          data-testid="gauge-marker"
          style={{
            position: "absolute",
            top: -4,
            left: `${position}%`,
            width: 16,
            height: 16,
            borderRadius: "50%",
            background: "white",
            border: "3px solid var(--brand-primary)",
            boxShadow: "0 0 8px rgba(139,92,246,0.4)",
            transform: "translateX(-50%)",
            transition: "left 0.2s ease",
          }}
        />
      </div>

      {/* Labels */}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          fontSize: 11,
          color: "var(--text-tertiary)",
          fontFamily: "var(--font-mono, 'DM Mono', monospace)",
        }}
      >
        <span>Underpriced</span>
        <span>Market Rate</span>
        <span>Premium</span>
      </div>

      {/* Accessibility warning for significantly below market */}
      {significantlyBelow && (
        <div
          data-testid="gauge-warning"
          style={{
            marginTop: 12,
            padding: "8px 12px",
            background: "rgba(245,158,11,0.08)",
            border: "1px solid rgba(245,158,11,0.2)",
            borderRadius: 8,
            fontSize: 12,
            color: "var(--warning)",
          }}
          role="alert"
        >
          This price is significantly below market average.
        </div>
      )}
    </div>
  )
}

