"use client"

import { useState, useCallback } from "react"
import { MarketPriceDisplay, type MarketPrices } from "./MarketPriceDisplay"
import { CompetitiveGauge } from "./CompetitiveGauge"
import { ShippingSelector } from "./ShippingSelector"
import { ConfirmationSummary } from "./ConfirmationSummary"
import type { ConditionCode } from "@/components/seller/ConditionGuide"

interface WizardStepPriceProps {
  // Card info
  cardName: string
  setName: string
  setCode: string
  collectorNumber: string
  condition: ConditionCode
  // Pricing state
  price: number // cents
  onPriceChange: (cents: number) => void
  // Shipping
  shippingMethod: string
  onShippingChange: (method: string) => void
  // Navigation
  onBack: () => void
  onPublish: () => void
  publishing: boolean
  publishError: string | null
  // Game code for price API
  gameCode: string
}

export function WizardStepPrice({
  cardName,
  setName,
  setCode,
  collectorNumber,
  condition,
  price,
  onPriceChange,
  shippingMethod,
  onShippingChange,
  onBack,
  onPublish,
  publishing,
  publishError,
  gameCode,
}: WizardStepPriceProps) {
  const [marketPrices, setMarketPrices] = useState<MarketPrices | null>(null)

  // Input displays dollars, state stores cents
  const [priceInput, setPriceInput] = useState(() => {
    return price > 0 ? (price / 100).toFixed(2) : ""
  })

  const handlePricesLoaded = useCallback(
    (prices: MarketPrices | null) => {
      setMarketPrices(prices)
      // Pre-fill price from median if no price set yet
      if (prices && price === 0) {
        onPriceChange(prices.median)
        setPriceInput((prices.median / 100).toFixed(2))
      }
    },
    [price, onPriceChange]
  )

  const handlePriceInput = (value: string) => {
    // Allow only valid price characters
    const cleaned = value.replace(/[^0-9.]/g, "")
    setPriceInput(cleaned)

    const dollars = parseFloat(cleaned)
    if (!isNaN(dollars) && dollars >= 0) {
      onPriceChange(Math.round(dollars * 100))
    }
  }

  const formatPrice = (cents: number) =>
    new Intl.NumberFormat("en-US", {
      style: "currency",
      currency: "USD",
    }).format(cents / 100)

  return (
    <div
      data-testid="wizard-step-price"
      style={{
        background: "var(--bg-surface-1)",
        border: "1px solid var(--border-default)",
        borderRadius: 16,
        padding: 32,
      }}
    >
      <h2
        style={{
          fontFamily: "var(--font-display, 'Barlow Condensed', sans-serif)",
          fontWeight: 700,
          fontSize: 24,
          color: "var(--text-primary)",
          marginBottom: 8,
        }}
      >
        Set Your Price
      </h2>
      <p
        style={{
          fontSize: 14,
          color: "var(--text-secondary)",
          marginBottom: 28,
          lineHeight: 1.6,
        }}
      >
        Based on recent market data for {cardName} ({condition}) from the last 30
        days.
      </p>

      {/* Market Prices */}
      <MarketPriceDisplay
        gameCode={gameCode}
        setCode={setCode}
        collectorNumber={collectorNumber}
        onPricesLoaded={handlePricesLoaded}
      />

      {/* Price Input */}
      <div style={{ marginBottom: 24 }}>
        <label
          style={{
            display: "block",
            fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
            fontSize: 13,
            fontWeight: 600,
            color: "var(--text-secondary)",
            marginBottom: 8,
          }}
        >
          Your Price
        </label>
        <div style={{ position: "relative" }}>
          <span
            style={{
              position: "absolute",
              left: 16,
              top: "50%",
              transform: "translateY(-50%)",
              fontSize: 20,
              fontWeight: 600,
              color: "var(--text-tertiary)",
              fontFamily: "var(--font-display, 'Barlow Condensed', sans-serif)",
            }}
          >
            $
          </span>
          <input
            data-testid="price-input"
            type="text"
            inputMode="decimal"
            value={priceInput}
            onChange={(e) => handlePriceInput(e.target.value)}
            placeholder="0.00"
            style={{
              width: "100%",
              padding: "12px 16px 12px 32px",
              background: "var(--bg-surface-2)",
              border: "1px solid var(--border-default)",
              borderRadius: 10,
              color: "var(--text-primary)",
              fontFamily: "var(--font-display, 'Barlow Condensed', sans-serif)",
              fontSize: 20,
              fontWeight: 600,
              outline: "none",
            }}
          />
        </div>
      </div>

      {/* Competitive Gauge — only show when market data is available */}
      {marketPrices && price > 0 && (
        <CompetitiveGauge
          price={price}
          low={marketPrices.low}
          high={marketPrices.high}
          median={marketPrices.median}
        />
      )}

      {/* Shipping */}
      <div style={{ marginBottom: 24 }}>
        <label
          style={{
            display: "block",
            fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
            fontSize: 13,
            fontWeight: 600,
            color: "var(--text-secondary)",
            marginBottom: 8,
          }}
        >
          Shipping
        </label>
        <ShippingSelector value={shippingMethod} onChange={onShippingChange} />
      </div>

      {/* Confirmation Summary */}
      <ConfirmationSummary
        cardName={cardName}
        setName={setName}
        setCode={setCode}
        collectorNumber={collectorNumber}
        condition={condition}
        price={price}
        shippingMethod={shippingMethod}
      />

      {/* Publish Error */}
      {publishError && (
        <div
          data-testid="publish-error"
          style={{
            marginTop: 16,
            padding: "12px 16px",
            background: "rgba(239,68,68,0.08)",
            border: "1px solid rgba(239,68,68,0.2)",
            borderRadius: 10,
            fontSize: 13,
            color: "var(--negative)",
          }}
        >
          {publishError}
        </div>
      )}

      {/* Actions */}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          marginTop: 28,
        }}
      >
        <button
          type="button"
          onClick={onBack}
          disabled={publishing}
          data-testid="wizard-back-btn"
          style={{
            fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
            fontWeight: 600,
            fontSize: 14,
            padding: "12px 28px",
            borderRadius: 12,
            background: "transparent",
            color: "var(--text-secondary)",
            border: "1px solid var(--border-default)",
            cursor: publishing ? "not-allowed" : "pointer",
            opacity: publishing ? 0.5 : 1,
          }}
        >
          ← Back
        </button>
        <button
          type="button"
          onClick={onPublish}
          disabled={publishing || price === 0}
          data-testid="wizard-publish-btn"
          style={{
            fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
            fontWeight: 600,
            fontSize: 15,
            padding: "14px 32px",
            borderRadius: 12,
            border: "none",
            cursor: publishing || price === 0 ? "not-allowed" : "pointer",
            background: "var(--brand-primary)",
            color: "white",
            boxShadow: "0 0 20px rgba(139,92,246,0.2)",
            opacity: publishing || price === 0 ? 0.6 : 1,
            display: "flex",
            alignItems: "center",
            gap: 8,
          }}
        >
          {publishing ? (
            <>
              <span
                style={{
                  width: 16,
                  height: 16,
                  border: "2px solid rgba(255,255,255,0.3)",
                  borderTop: "2px solid white",
                  borderRadius: "50%",
                  animation: "spin 0.8s linear infinite",
                  display: "inline-block",
                }}
              />
              Publishing...
            </>
          ) : (
            "Publish Listing ✓"
          )}
        </button>
      </div>

      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  )
}

