  shippingMethod: string
}

interface ListingWizardProps {
  prefillSku?: string
}

interface PublishResult {
  title: string
  price: number
  condition: string
  status: "published" | "draft"
}

export function ListingWizard({ prefillSku }: ListingWizardProps) {
  const router = useRouter()

  const [state, setState] = useState<WizardState>({
    currentStep: 1,
    selectedCard: null,
    selectedPrint: null,
    condition: "NM",
    language: "EN",
    photos: [],
    description: "",
    price: 0,
    shippingMethod: "standard",
  })

  const [prefillLoading, setPrefillLoading] = useState(!!prefillSku)
  const [prefillError, setPrefillError] = useState<string | null>(null)
  const [publishing, setPublishing] = useState(false)
  const [publishError, setPublishError] = useState<string | null>(null)
  const [publishResult, setPublishResult] = useState<PublishResult | null>(null)

  // Pre-fill from SKU
  useEffect(() => {
    if (!prefillSku) return

    let cancelled = false

    async function fetchSkuData() {
      try {
        const response = await fetch(
          `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/catalog/sku/${encodeURIComponent(prefillSku!)}`
        )

        if (!response.ok) {
          throw new Error(`Failed to fetch card data (${response.status})`)
        }

        const data = await response.json()

        if (cancelled) return

        const card: CardSearchResult = {
          id: data.cardId || data.id || "",
          name: data.cardName || data.name || "",
          setName: data.setName || "",
          rarity: data.rarity || "",
          imageUrl: data.imageUrl || undefined,
          prints: (data.prints || data.printings || []).map(
            (p: Record<string, unknown>) => ({
              id: p.id || "",
              setName: p.setName || p.set_name || "",
              setCode: p.setCode || p.set_code || "",
              collectorNumber: p.collectorNumber || p.collector_number || "",
              imageUrl: p.imageUrl || p.image_url || undefined,
            })
          ),
        }

        // Try to find the specific printing from the SKU data
        const matchingPrint: PrintOption | null =
          card.prints.find(
            (p) =>
              p.setCode === (data.setCode || "") &&
              p.collectorNumber === (data.collectorNumber || "")
          ) ||
          card.prints[0] ||
          null

        setState((prev) => ({
          ...prev,
          currentStep: 2,
          selectedCard: card,
          selectedPrint: matchingPrint,
        }))
      } catch (err) {
        if (cancelled) return
        const message =
          err instanceof Error ? err.message : "Failed to load card data"
        console.error("[listing-wizard] SKU prefill failed:", message)
        setPrefillError(message)
      } finally {
        if (!cancelled) setPrefillLoading(false)
      }
    }

    fetchSkuData()
    return () => {
      cancelled = true
    }
  }, [prefillSku])

  const completedSteps = getCompletedSteps(state)

  const handleCardSelect = useCallback((card: CardSearchResult) => {
    setState((prev) => ({
      ...prev,
      selectedCard: card,
      selectedPrint: null, // Reset print when card changes
    }))
  }, [])

  const handlePrintSelect = useCallback((print: PrintOption) => {
    setState((prev) => ({
      ...prev,
      selectedPrint: print,
    }))
  }, [])

  const goToStep = useCallback((step: 1 | 2 | 3) => {
    setState((prev) => ({ ...prev, currentStep: step }))
  }, [])

  const handleConditionChange = useCallback((condition: ConditionCode) => {
    setState((prev) => ({ ...prev, condition }))
  }, [])

  const handlePhotosChange = useCallback((photos: string[]) => {
    setState((prev) => ({ ...prev, photos }))
  }, [])

  const handleDescriptionChange = useCallback((description: string) => {
    setState((prev) => ({ ...prev, description }))
  }, [])

  const handlePriceChange = useCallback((price: number) => {
    setState((prev) => ({ ...prev, price }))
  }, [])

  const handleShippingChange = useCallback((shippingMethod: string) => {
    setState((prev) => ({ ...prev, shippingMethod }))
  }, [])

  const handleUploadImage = useCallback(async (file: File): Promise<string | null> => {
    return uploadListingImage(file)
  }, [])

  const handlePublish = useCallback(async () => {
    if (!state.selectedCard || !state.selectedPrint) return

    setPublishing(true)
    setPublishError(null)

    try {
      const print = state.selectedPrint

      // Build catalog_sku: game-set-number-language-condition-finish
      // Infer game from context — default to MTG for now
      const gameCode = "MTG"
      const catalogSku = `${gameCode}-${print.setCode}-${print.collectorNumber}-${state.language}-${state.condition}-NORMAL`

      const payload: CreateListingInput = {
        catalog_sku: catalogSku,
        condition: state.condition,
        language: state.language,
        price: state.price,
        title: `${state.selectedCard.name} (${state.condition})`,
        description: state.description || undefined,
        images: state.photos.length > 0 ? state.photos : undefined,
        shipping_method: state.shippingMethod as "standard" | "priority" | "free_over_25",
      }

      const result = await createSellerListing(payload)

      if (!result) {
        throw new Error("Failed to create listing. Please try again.")
      }

      setPublishResult({
        title: result.title,
        price: result.price,
        condition: state.condition,
        status: result.status,
      })
    } catch (err) {
      const message =
        err instanceof Error ? err.message : "Failed to create listing"
      console.error("[listing-wizard] Listing creation failed:", message)
      setPublishError(message)
    } finally {
      setPublishing(false)
    }
  }, [state])

  const handleListAnother = useCallback(() => {
    setState({
      currentStep: 1,
      selectedCard: null,
      selectedPrint: null,
      condition: "NM",
      language: "EN",
      photos: [],
      description: "",
      price: 0,
      shippingMethod: "standard",
    })
    setPublishResult(null)
    setPublishError(null)
  }, [])

  if (prefillLoading) {
    return (
      <div
        data-testid="wizard-loading"
        style={{
          display: "flex",
          justifyContent: "center",
          padding: 48,
          color: "var(--text-tertiary)",
          fontSize: 14,
        }}
      >
        Loading card data...
      </div>
    )
  }

  if (prefillError) {
    return (
      <div
        data-testid="wizard-prefill-error"
        style={{
          padding: 24,
          background: "rgba(239,68,68,0.08)",
          border: "1px solid rgba(239,68,68,0.2)",
          borderRadius: 12,
          color: "var(--negative)",
          fontSize: 14,
          textAlign: "center",
        }}
      >
        {prefillError}
      </div>
    )
  }

  // Success screen
  if (publishResult) {
    return (
      <div data-testid="listing-wizard">
        <WizardProgress currentStep={3} completedSteps={[1, 2, 3]} />
        <div
          data-testid="wizard-success"
          style={{
            background: "var(--bg-surface-1)",
            border: "1px solid var(--border-default)",
            borderRadius: 16,
            padding: 32,
          }}
        >
          <ListingSuccessScreen
            title={publishResult.title}
            price={publishResult.price}
            condition={publishResult.condition}
            status={publishResult.status}
            onViewListing={() => router.push("/seller/dashboard/listings")}
            onListAnother={handleListAnother}
            onClose={() => router.push("/sell")}
          />
        </div>
      </div>
    )
  }

  return (
    <div data-testid="listing-wizard">
      <WizardProgress currentStep={state.currentStep} completedSteps={completedSteps} />

      {state.currentStep === 1 && (
        <WizardStepIdentify
          selectedCard={state.selectedCard}
          selectedPrint={state.selectedPrint}
          onCardSelect={handleCardSelect}
          onPrintSelect={handlePrintSelect}
          onContinue={() => goToStep(2)}
        />
      )}

      {state.currentStep === 2 && (
        <WizardStepCondition
          condition={state.condition}
          photos={state.photos}
          description={state.description}
          onConditionChange={handleConditionChange}
          onPhotosChange={handlePhotosChange}
          onDescriptionChange={handleDescriptionChange}
          onBack={() => goToStep(1)}
          onContinue={() => goToStep(3)}
          uploadImage={handleUploadImage}
        />
      )}

      {state.currentStep === 3 && state.selectedCard && state.selectedPrint && (
        <WizardStepPrice
          cardName={state.selectedCard.name}
          setName={state.selectedPrint.setName}
          setCode={state.selectedPrint.setCode}
          collectorNumber={state.selectedPrint.collectorNumber}
          condition={state.condition}
          price={state.price}
          onPriceChange={handlePriceChange}
          shippingMethod={state.shippingMethod}
          onShippingChange={handleShippingChange}
          onBack={() => goToStep(2)}
          onPublish={handlePublish}
          publishing={publishing}
          publishError={publishError}
          gameCode="MTG"
        />
      )}
    </div>
  )
}

function getCompletedSteps(state: WizardState): number[] {
  const completed: number[] = []

  // Step 1 complete when card + print selected
  if (state.selectedCard && state.selectedPrint) {
    completed.push(1)
  }

  // Step 2 complete when condition is set (always has default)
  if (state.selectedCard && state.selectedPrint) {
    completed.push(2)
  }

  return completed
}

