describe("CompetitiveGauge", () => {
  it("renders gauge with marker", () => {
    render(
      <CompetitiveGauge price={5899} low={5200} high={6850} median={5899} />
    )

    expect(screen.getByTestId("competitive-gauge")).toBeInTheDocument()
    expect(screen.getByTestId("gauge-marker")).toBeInTheDocument()
    expect(screen.getByText("Underpriced")).toBeInTheDocument()
    expect(screen.getByText("Market Rate")).toBeInTheDocument()
    expect(screen.getByText("Premium")).toBeInTheDocument()
  })

  it("shows warning when price is significantly below median", () => {
    render(
      <CompetitiveGauge price={2000} low={5200} high={6850} median={5899} />
    )

    expect(screen.getByTestId("gauge-warning")).toBeInTheDocument()
    expect(
      screen.getByText("This price is significantly below market average.")
    ).toBeInTheDocument()
  })

  it("does not show warning at normal price", () => {
    render(
      <CompetitiveGauge price={5500} low={5200} high={6850} median={5899} />
    )

    expect(screen.queryByTestId("gauge-warning")).not.toBeInTheDocument()
  })

  it("positions marker based on price relative to range", () => {
    render(
