// --- Publish flow integration ---

describe("ListingWizard publish flow", () => {
  beforeEach(() => {
    vi.useFakeTimers({ shouldAdvanceTime: true })
    mockCreateSellerListing.mockReset()
    mockUploadListingImage.mockReset()
    mockPush.mockReset()
  })

  afterEach(() => {
    vi.useRealTimers()
    vi.restoreAllMocks()
  })

  it("publish creates listing and shows success screen", async () => {
    // Mock the search, price, and listing creation APIs
    global.fetch = vi.fn()
      .mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve({ cards: [mockCard] }),
      })
      .mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve({ low: 5200, median: 5899, high: 6850 }),
      })

    mockCreateSellerListing.mockResolvedValue({
      listing_id: "listing-1",
      title: "Ragavan, Nimble Pilferer (NM)",
      handle: "ragavan-nm",
      status: "published",
      thumbnail: null,
      variant_id: "var-1",
      sku: "MTG-MH2-138-EN-NM-NORMAL",
      price: 5899,
      quantity: 1,
      condition: "NM",
      shipping_method: "standard",
    })

    render(<ListingWizard />)

    // Step 1: Search and select card
    const input = screen.getByTestId("card-search-field")
    await act(async () => {
      fireEvent.change(input, { target: { value: "Ragavan" } })
    })
    await act(async () => {
      vi.advanceTimersByTime(350)
    })
    await waitFor(() => {
      expect(screen.getByTestId("card-search-results")).toBeInTheDocument()
    })
    await act(async () => {
      fireEvent.click(screen.getByTestId("card-search-result-item"))
    })
    await waitFor(() => {
      expect(screen.getByTestId("printing-grid")).toBeInTheDocument()
    })
    await act(async () => {
      fireEvent.click(screen.getAllByTestId("printing-option")[0])
    })
    await act(async () => {
      fireEvent.click(screen.getByTestId("wizard-continue-btn"))
    })

    // Step 2: Condition (default NM is fine)
    await waitFor(() => {
      expect(screen.getByTestId("wizard-step-condition")).toBeInTheDocument()
    })
    await act(async () => {
      fireEvent.click(screen.getByTestId("wizard-continue-btn"))
    })

    // Step 3: Price + Publish
    await waitFor(() => {
      expect(screen.getByTestId("wizard-step-price")).toBeInTheDocument()
    })

    // Wait for market prices to load and pre-fill
    await waitFor(() => {
      const priceInput = screen.getByTestId("price-input") as HTMLInputElement
      expect(priceInput.value).toBe("58.99")
    })

    // Click Publish
    await act(async () => {
      fireEvent.click(screen.getByTestId("wizard-publish-btn"))
    })

    // Should show success screen
    await waitFor(() => {
      expect(screen.getByTestId("wizard-success")).toBeInTheDocument()
    })

    expect(mockCreateSellerListing).toHaveBeenCalledWith(
      expect.objectContaining({
        catalog_sku: "MTG-MH2-138-EN-NM-NORMAL",
        condition: "NM",
        price: 5899,
        title: "Ragavan, Nimble Pilferer (NM)",
      })
    )
  })

  it("back buttons preserve state when navigating between steps", async () => {
    global.fetch = vi.fn()
      .mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve({ cards: [mockCard] }),
      })
      .mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve({ low: 5200, median: 5899, high: 6850 }),
      })

    render(<ListingWizard />)

    // Navigate to step 2
    const input = screen.getByTestId("card-search-field")
    await act(async () => {
      fireEvent.change(input, { target: { value: "Ragavan" } })
    })
    await act(async () => {
      vi.advanceTimersByTime(350)
    })
    await waitFor(() => {
      expect(screen.getByTestId("card-search-results")).toBeInTheDocument()
    })
    await act(async () => {
      fireEvent.click(screen.getByTestId("card-search-result-item"))
    })
    await waitFor(() => {
      expect(screen.getByTestId("printing-grid")).toBeInTheDocument()
    })
    await act(async () => {
      fireEvent.click(screen.getAllByTestId("printing-option")[0])
    })
    await act(async () => {
      fireEvent.click(screen.getByTestId("wizard-continue-btn"))
    })

    // On step 2 — change condition
    await waitFor(() => {
      expect(screen.getByTestId("wizard-step-condition")).toBeInTheDocument()
    })
    await act(async () => {
      fireEvent.click(screen.getByTestId("condition-option-LP"))
    })

    // Go back to step 1
    await act(async () => {
      fireEvent.click(screen.getByTestId("wizard-back-btn"))
    })

    // Card should still be selected
    await waitFor(() => {
      expect(screen.getByTestId("wizard-step-identify")).toBeInTheDocument()
    })
    expect(screen.getByTestId("printing-grid")).toBeInTheDocument()

    // Go forward again to step 2
    await act(async () => {
      fireEvent.click(screen.getByTestId("wizard-continue-btn"))
    })

    // Condition should still be LP
    await waitFor(() => {
      expect(screen.getByTestId("wizard-step-condition")).toBeInTheDocument()
    })
    const lpOption = screen.getByTestId("condition-option-LP")
    expect(lpOption).toHaveAttribute("aria-checked", "true")
  })
})

// --- Voltage compliance ---

describe("Voltage token compliance", () => {
  it("no forbidden Tailwind color classes in wizard sources", async () => {
    // This test checks that we don't use bg-white, bg-gray-*, text-gray-* in wizard components
    // It's verified at build time via grep in slice verification, but we also assert at runtime
    // by checking that none of the rendered elements use those classes
    render(<ListingWizard />)

    const wizard = screen.getByTestId("listing-wizard")
    const html = wizard.innerHTML

    expect(html).not.toContain("bg-white")
    expect(html).not.toMatch(/bg-gray-/)
    expect(html).not.toMatch(/text-gray-/)
  })
})

